import type { CefrLevel, VocabCard, VocabDeck } from './types'

const today = new Date().toISOString()

type DeckPattern = 'verb-object' | 'prep-noun' | 'expression'

interface PhrasePart {
  fr: string
  en: string
}

interface BulkDeckSpec {
  id: string
  title: string
  description: string
  level: CefrLevel
  tags: string[]
  pattern: DeckPattern
  left: PhrasePart[]
  right: PhrasePart[]
}

const makeExampleFr = (frontFr: string) => `Je revise : ${frontFr}.`
const makeExampleEn = (backEn: string) => `Review card: ${backEn}.`

const buildPairs = (pattern: DeckPattern, left: PhrasePart[], right: PhrasePart[]) => {
  const pairs: Array<{ frontFr: string; backEn: string }> = []

  for (const first of left) {
    for (const second of right) {
      const separator =
        pattern === 'verb-object'
          ? ' '
          : pattern === 'prep-noun'
          ? ' '
          : ''

      pairs.push({
        frontFr: `${first.fr}${separator}${second.fr}`.trim(),
        backEn: `${first.en}${separator}${second.en}`.trim(),
      })
    }
  }

  return pairs.slice(0, 100)
}

