export const bulkDecks: VocabDeck[] = deckSpecs.map((deck, index) => ({
  id: deck.id,
  title: deck.title,
  description: deck.description,
  level: deck.level,
  tags: deck.tags,
  difficulty: deck.level === 'A1' ? 1 : deck.level === 'A2' ? 2 : deck.level === 'B1' ? 3 : 4,
  estimatedMinutes: 20,
  sequence: 700 + index,
  source: 'seed',
}))

export const bulkCards: VocabCard[] = deckSpecs.flatMap((deck, deckIndex) =>
  buildPairs(deck.pattern, deck.left, deck.right).map((pair, pairIndex) => ({
    id: `bulk-card-${deckIndex + 1}-${pairIndex + 1}`,
    deckId: deck.id,
    frontFr: pair.frontFr,
    backEn: pair.backEn,
    exampleFr: makeExampleFr(pair.frontFr),
    exampleEn: makeExampleEn(pair.backEn),
    notes: 'Generated level-based vocabulary card.',
    tags: [...deck.tags, 'generated'],
    confidence: 0,
    dueAt: today,
    intervalDays: 1,
    source: 'seed',
  })),
)
